import { sortNotesByUpdatedAt } from './path/to/your/module';

describe('sortNotesByUpdatedAt', () => {
  it('should handle happy path: correctly sort notes by updatedAt descending', () => {
    const notes = [
      { id: 1, updatedAt: '2023-01-01T10:00:00Z' },
      { id: 2, updatedAt: '2023-02-01T12:00:00Z' },
      { id: 3, updatedAt: '2023-01-15T09:30:00Z' },
    ];

    const sorted = sortNotesByUpdatedAt(notes);
    expect(sorted.map(n => n.id)).toEqual([2, 3, 1]); // 2 > 3 > 1 by date
  });

  it('should handle edge case: notes with identical updatedAt timestamps stay in original order', () => {
    const notes = [
      { id: 'a', updatedAt: '2023-03-01T08:00:00Z' },
      { id: 'b', updatedAt: '2023-03-01T08:00:00Z' },
      { id: 'c', updatedAt: '2023-02-01T08:00:00Z' },
    ];

    const sorted = sortNotesByUpdatedAt(notes);
    expect(sorted.map(n => n.id)).toEqual(['a', 'b', 'c']); // a and b keep relative order
  });

  it('should handle null/empty input: returns empty array and does not throw', () => {
    expect(sortNotesByUpdatedAt(null as any)).toEqual([]);
    expect(sortNotesByUpdatedAt(undefined as any)).toEqual([]);
    expect(sortNotesByUpdatedAt([])).toEqual([]);
    expect(() => sortNotesByUpdatedAt(null as any)).not.toThrow();
  });
});

